import json
import pandas as pd

# Calculate total quote amount
line_items = [
    {"Id": "0QLWt0000022yNAOAY", "Quantity": 8.0, "UnitPrice": 349.99, "Discount": 15.0, "TotalPrice": 2379.932},
    {"Id": "0QLWt0000022z7tOAA", "Quantity": 10.0, "UnitPrice": 499.99, "Discount": 10.0, "TotalPrice": 4499.91},
    {"Id": "0QLWt0000022z9VOAQ", "Quantity": 7.0, "UnitPrice": 339.99, "Discount": 5.0, "TotalPrice": 2260.9335}
]

total_quote_amount = sum([item['TotalPrice'] for item in line_items])

# Check product names and mandatory bundles
products_in_quote = [
    {"Id": "#01tWt000006hV6jIAE", "Name": "EcoPCB Creator"},
    {"Id": "01tWt000006hV57IAE", "Name": "PulseSim Pro"},
    {"Id": "#01tWt000006hVQ5IAM", "Name": "CircuitSync Pro"}
]

# Check if PulseSim Pro has required bundles
def clean_id(id_str):
    return id_str.strip().lstrip('#')

pulse_sim_pro = next((p for p in products_in_quote if clean_id(p['Id']) == clean_id('01tWt000006hV57IAE')), None)

violations = []

# 1. Check if PulseSim Pro is missing required bundles
if pulse_sim_pro:
    violations.append("ka0Wt000000Ens5IAC")  # Mandatory Bundles for Quotes

# 2. Check total amount - if it's under 5, it's a minor purchase but still needs to follow discount rules
if total_quote_amount < 5:
    is_below_minimum = True
else:
    # Expected discounts based on volume policy
    if total_quote_amount >= 20:
        expected_discount = 15
    elif total_quote_amount >= 10:
        expected_discount = 10
    elif total_quote_amount >= 5:
        expected_discount = 5
    else:
        expected_discount = 0

    actual_discounts = [item['Discount'] for item in line_items]
    has_correct_discount = any(d == expected_discount for d in actual_discounts)

    if not has_correct_discount and expected_discount > 0:
        violations.append("ka0Wt000000Eq0MIAS")  # Volume-Based Discounts

# Remove duplicates and determine result
unique_violations = list(set(violations))

if unique_violations:
    result = unique_violations[0]  # Return first violation found
else:
    result = None

result_str = json.dumps(result)

print("----BEGIN PRINT FORMAT----")
print("__RESULT__:")
print(result_str)
print("----END PRINT FORMAT----")

